/**
 * Subscribe for exactly one emission of an event, then auto-unsubscribe.
 * Returns a token that can be passed to unsubscribe() to cancel early.
 */
once<T = unknown>(event: string, handler: EventHandler<T>): symbol {
  let token: symbol
  const wrappedHandler: EventHandler<T> = (data: T) => {
    this.unsubscribe(token)
    handler(data)
  }
  token = this.subscribe(event, wrappedHandler)
  return token
}
```

**Note:** This implementation requires `unsubscribe()` to be implemented first. Here's the implementation for that as well:

```typescript
/**
 * Unsubscribe using a token returned by subscribe().
 * Returns true if the token was found and removed, false otherwise.
 */
unsubscribe(token: symbol): boolean {
  const event = this.tokenIndex.get(token)
  if (!event) return false
  const handlers = this.subs.get(event)
  if (!handlers) return false
  const deleted = handlers.delete(token)
  if (deleted) {
    this.tokenIndex.delete(token)
    if (handlers.size === 0) {
      this.subs.delete(event)
    }
  }
  return deleted
}
```

The `once()` implementation wraps the user's handler in a closure that unsubscribes before calling the original handler. This ensures the handler fires exactly once, and the token can still be used to cancel early if needed.

