    this.failureCount++
    this.lastFailureTime = this.clock()
    if (this.failureCount >= this.failureThreshold) {
      this.state = 'OPEN'
      this.halfOpenAttempted = false
    }
  }
}
```

**Result**: Only the first concurrent call executes the probe; the second is rejected with `CircuitOpenError`. Scenario 3 now correctly re-opens on the second failure.

