async acquire(_cost = 1, _timeoutMs = 0): Promise<boolean> {
  const cost = _cost
  const timeoutMs = _timeoutMs

  try {
    this.consume(cost)
    return true
  } catch (error) {
    if (!(error instanceof RateLimiterExceededError)) {
      throw error
    }

    const requiredWaitMs = error.retryAfterMs
    if (requiredWaitMs > timeoutMs) {
      return false
    }

    await new Promise(resolve => setTimeout(resolve, requiredWaitMs))
    this.consume(cost)
    return true
  }
}
